  "inlineSchema": "generator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"debian-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// Módulos del sistema (agregables bajo demanda)\nmodel Modulo {\n  id          Int         @id @default(autoincrement())\n  nombre      String      @unique\n  descripcion String?\n  icono       String? // Icono para el menú\n  orden       Int         @default(0)\n  activo      Boolean     @default(true)\n  permisos    Permiso[]\n  roles       RolModulo[]\n  createdAt   DateTime    @default(now())\n}\n\n// Roles del sistema (admin, viewer, o personalizados)\nmodel Rol {\n  id          Int          @id @default(autoincrement())\n  nombre      String       @unique\n  descripcion String?\n  esBase      Boolean      @default(false) // true para admin y viewer\n  roles       RolModulo[] // Relación muchos a muchos con módulos\n  permisos    Permiso[] // Permisos asignados al rol\n  usuarios    UsuarioRol[]\n  createdAt   DateTime     @default(now())\n}\n\n// Relación muchos a muchos Rol-Modulo (qué módulos tiene cada rol)\nmodel RolModulo {\n  rolId    Int\n  moduloId Int\n  rol      Rol    @relation(fields: [rolId], references: [id], onDelete: Cascade)\n  modulo   Modulo @relation(fields: [moduloId], references: [id], onDelete: Cascade)\n\n  @@id([rolId, moduloId])\n}\n\n// Permisos por módulo (ver, crear, editar, eliminar, exportar)\nmodel Permiso {\n  id       Int    @id @default(autoincrement())\n  moduloId Int\n  accion   String // ver, crear, editar, eliminar, exportar\n  modulo   Modulo @relation(fields: [moduloId], references: [id], onDelete: Cascade)\n  rol      Rol?   @relation(fields: [rolId], references: [id], onDelete: Cascade)\n  rolId    Int?\n\n  @@unique([moduloId, accion])\n}\n\n// Relación muchos a muchos usuarios-roles\nmodel UsuarioRol {\n  usuarioId Int\n  rolId     Int\n  usuario   User @relation(fields: [usuarioId], references: [id], onDelete: Cascade)\n  rol       Rol  @relation(fields: [rolId], references: [id], onDelete: Cascade)\n\n  @@id([usuarioId, rolId])\n}\n\nmodel User {\n  id                Int          @id @default(autoincrement())\n  email             String       @unique\n  password          String\n  nombre            String\n  rol               String       @default(\"user\")\n  activo            Boolean      @default(true)\n  debeCambiarPass   Boolean      @default(false) // Forzar cambio de contraseña\n  passwordChangedAt DateTime? // Última vez que cambió la contraseña\n  usuarioRoles      UsuarioRol[]\n  createdAt         DateTime     @default(now())\n  updatedAt         DateTime     @updatedAt\n}\n\nmodel Servidor {\n  id               Int      @id @default(autoincrement())\n  pais             String\n  host             String\n  nombreVM         String?\n  ip               String?\n  cpu              Int?\n  memoria          String?\n  disco            String?\n  ambiente         String\n  arquitectura     String?\n  sistemaOperativo String?\n  version          String?\n  antivirus        String?\n  estado           String\n  responsable      String?\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n}\n\nmodel InventarioFisico {\n  id               Int      @id @default(autoincrement())\n  pais             String\n  categoria        String\n  marca            String\n  modelo           String?\n  serie            String?\n  inventario       String?\n  estado           String\n  responsable      String?\n  observaciones    String?\n  equipo           String?\n  direccionIp      String?\n  ilo              String?\n  descripcion      String?\n  serial           String?\n  sistemaOperativo String?\n  garantia         String?\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n}\n\nmodel InventarioCloud {\n  id               Int      @id @default(autoincrement())\n  tenant           String?\n  nube             String?\n  instanceName     String?\n  ipPublica        String?\n  ipPrivada        String?\n  instanceType     String?\n  cpu              Int?\n  ram              String?\n  storageGib       String?\n  sistemaOperativo String?\n  costoUsd         String?\n  hostName         String?\n  responsable      String?\n  modoUso          String?\n  service          String?\n  antivirus        String?\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n}\n\nmodel Configuracion {\n  id        Int      @id @default(autoincrement())\n  clave     String   @unique\n  valor     String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel EmailConfig {\n  id         Int      @id @default(autoincrement())\n  host       String\n  puerto     Int      @default(587)\n  usuario    String\n  contrasena String\n  usandoTls  Boolean  @default(true)\n  emailFrom  String\n  activo     Boolean  @default(true)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n}\n\n// ============================================\n// AUDIT LOG - Historial de cambios\n// ============================================\nmodel AuditLog {\n  id           Int      @id @default(autoincrement())\n  usuarioId    Int?\n  usuario      String? // Nombre o email del usuario\n  accion       String // login, create, update, delete, export, import\n  entidad      String // User, Servidor, InventarioFisico, etc.\n  entidadId    Int? // ID del registro afectado\n  datosPrevios String? // JSON con datos anteriores\n  datosNuevos  String? // JSON con datos nuevos\n  ip           String?\n  userAgent    String?\n  createdAt    DateTime @default(now())\n}\n",
